public void testParseInto_monthDay_withDefaultYear_nonLeapYear() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withDefaultYear(2001);
    MutableDateTime result = new MutableDateTime(2004, 1, 9, 12, 20, 30, 0, LONDON);
    assertEquals(4, f.parseInto(result, "2 28", 0));
    assertEquals(new MutableDateTime(2004, 2, 28, 12, 20, 30, 0, LONDON), result);
}

public void testParseInto_dayOnly_withDefaultYear() {
    DateTimeFormatter f = DateTimeFormat.forPattern("d").withDefaultYear(2000);
    MutableDateTime result = new MutableDateTime(2004, 3, 15, 12, 20, 30, 0, LONDON);
    assertEquals(2, f.parseInto(result, "25", 0));
    assertEquals(new MutableDateTime(2004, 3, 25, 12, 20, 30, 0, LONDON), result);
}

public void testParseInto_monthDay_withDefaultYear_leapToNonLeap() {
    DateTimeFormatter f = DateTimeFormat.forPattern("M d").withDefaultYear(2012);
    MutableDateTime result = new MutableDateTime(2003, 1, 9, 12, 20, 30, 0, LONDON);
    assertEquals(4, f.parseInto(result, "2 29", 0));
    assertEquals(new MutableDateTime(2003, 2, 28, 12, 20, 30, 0, LONDON), result);
}
